<?php declare(strict_types=1);use App\Support\View;$base='/projects/'.$project->id.'/work-packages/'.$workPackage->id;$effortTotals=$effortTotals??new App\Models\HourTotals('0.00','0.00',0);$unifiedEffortTotals=$unifiedEffortTotals??$effortTotals;$divergentEffortCount=$divergentEffortCount??0;$recentAllocations=$recentAllocations??[];$converter=$converter??new App\Support\PersonMonthConverter();$hasAllocations=$hasAllocations??false;?>
<div class="d-flex justify-content-between align-items-start mb-4"><div><p class="text-secondary"><?= View::escape($project->displayTitle()) ?></p><h1><?= View::escape($workPackage->displayTitle()) ?></h1></div><div class="d-flex gap-2"><a class="btn btn-outline-secondary" href="<?= View::escape($urls->to('/projects/'.$project->id.'/work-packages')) ?>">All Work Packages</a><?php if($canManage):?><a class="btn btn-primary" href="<?= View::escape($urls->to($base.'/edit')) ?>">Edit</a><?php endif;?></div></div>
<?php foreach($workPackage->warnings()as$warning):?><div class="alert alert-warning"><?= View::escape($warning) ?></div><?php endforeach;?>
<div class="card card-body"><dl class="row mb-0"><?php foreach(['Project'=>$workPackage->projectName(),'Code'=>$workPackage->code,'Title'=>$workPackage->title,'Description'=>$workPackage->description,'Period'=>$workPackage->period(),'Responsible participant'=>$workPackage->responsibleName(),'Responsible project role'=>$workPackage->responsibleRoleLabel(),'State'=>$workPackage->isActive?'Active':'Inactive','Created'=>$workPackage->createdAt->format('Y-m-d H:i'),'Updated'=>$workPackage->updatedAt->format('Y-m-d H:i')]as$l=>$v):?><dt class="col-md-3"><?= View::escape($l) ?></dt><dd class="col-md-9"><?= nl2br(View::escape($v??'—')) ?></dd><?php endforeach;?><?php if($canViewNotes):?><dt class="col-md-3">Private notes</dt><dd class="col-md-9"><?= nl2br(View::escape($workPackage->notes??'—')) ?></dd><?php endif;?></dl></div>
<section class="mt-5"><h2 class="h4">Person-hours</h2><p class="text-secondary">Unified values include only rows whose stored planned and actual values agree; PM uses <?= View::escape($project->hoursPerPm) ?> hours/PM.</p><?php if($divergentEffortCount>0):?><div class="alert alert-warning"><?= $divergentEffortCount ?> divergent record<?= $divergentEffortCount===1?' is':'s are' ?> excluded. Use allocation details to reconcile it.</div><?php endif;?><div class="row g-3"><?php foreach(['Person-hours'=>$unifiedEffortTotals->plannedHours,'Person-Months'=>$converter->convert($unifiedEffortTotals->plannedHours,$project->hoursPerPm),'Participants'=>(string)$unifiedEffortTotals->participantCount,'Distinct months'=>(string)$unifiedEffortTotals->distinctMonthCount]as$l=>$v):?><div class="col-sm-6 col-lg"><div class="card card-body"><small class="text-secondary"><?= View::escape($l) ?></small><strong><?= View::escape($v) ?></strong></div></div><?php endforeach;?></div><?php if($recentAllocations!==[]):?><h3 class="h6 mt-4">Advanced stored-value review</h3><div class="table-responsive mt-3"><table class="table table-striped"><thead><tr><th>Participant</th><th>Month</th><th>Planned</th><th>Actual</th></tr></thead><tbody><?php foreach($recentAllocations as$a):?><tr><td><?= View::escape($a->personName) ?></td><td><?= View::escape($a->monthLabel()) ?></td><td><?= View::escape($a->plannedHours??'—') ?></td><td><?= View::escape($a->actualHours??'—') ?></td></tr><?php endforeach;?></tbody></table></div><?php endif;?></section>
<?php if($canManage):?><div class="d-flex gap-2 mt-4"><form method="post" action="<?= View::escape($urls->to($base.'/'.($workPackage->isActive?'deactivate':'activate'))) ?>"><input type="hidden" name="_csrf" value="<?= View::escape($csrfToken) ?>"><button class="btn btn-outline-primary"><?= $workPackage->isActive?'Deactivate':'Activate' ?></button></form><a class="btn btn-outline-danger" href="<?= View::escape($urls->to($base.'/remove')) ?>">Remove</a></div><?php endif;?>
